// Gera relatório semanal
const now = new Date();
const weekAgo = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

// Simula busca de métricas
const metricas = {
  total_leads: 47,
  leads_hot: 12,
  leads_warm: 18,
  leads_cold: 17,
  capital_total: 12500000,
  convertidos: 5,
  taxa_conversao: 10.6
};

const ranking = [
  { nome: 'João Silva', leads: 15, convertidos: 3 },
  { nome: 'Maria Santos', leads: 12, convertidos: 2 },
  { nome: 'Pedro Costa', leads: 10, convertidos: 0 }
];

return {
  json: {
    periodo: {
      inicio: weekAgo.toISOString(),
      fim: now.toISOString()
    },
    metricas,
    ranking
  }
};

